// ----------------------------
// Helper: Format itinerary description
// ----------------------------
function formatDescription(text) {
    if (!text) return '';

    return text
        .replace(
            /\(📍\s*([^(]+)\(([^)]+)\)\)/g,
            '<a href="$2" target="_blank" style="color:#2563EB;font-weight:bold;text-decoration:none;white-space:nowrap;">📍 $1</a>'
        )
        .replace(/\\n/g, '<br>')
        .replace(/\n/g, '<br>')
        .replace(
            /(Morning:|Afternoon:|Evening:)/g,
            '<strong style="color:#111827;">$1</strong>'
        );
}

// ----------------------------
// Extract map links from itinerary
// ----------------------------
function extractMapLinks(text) {

    if (!text) return [];

    const regex = /\(📍\s*([^(]+)\(([^)]+)\)\)/g;

    const links = [];
    let match;

    while ((match = regex.exec(text)) !== null) {

        links.push({
            name: match[1].trim(),
            mapLink: match[2].trim()
        });

    }

    return links;
}

