  { label: "12 Submissions",      amount: 10.00, type: "submissions", value: 12 },
  { label: "20 Credits (Bundle)", amount: 16.00, type: "credits",     value: 20 },
  { label: "10 Credits (Bundle)", amount: 9.00,  type: "credits",     value: 10 },
  { label: "5 Credits (Bundle)",  amount: 5.00,  type: "credits",     value: 5  },
  { label: "1 Credit",            amount: 1.00,  type: "credits",     value: 1  },
];

// ---------- GET VALUES ----------
const paymentName  = input.name;
const paymentEmail = input.email;

const dbName  = input["Full Name"];
const dbEmail = input["Email"];

// ---------- CHECK PERSON MATCH ----------
const nameMatch  = paymentName === dbName;
const emailMatch = paymentEmail === dbEmail;

const isSamePerson = nameMatch && emailMatch;

// ---------- PRODUCT MATCH ----------
const amountEUR = input.amount_eur ? parseFloat(input.amount_eur) : null;

const matchedProduct =
  amountEUR !== null
    ? PRODUCTS.find(p => Math.abs(p.amount - amountEUR) < 0.001)
    : null;

const productLabel = matchedProduct?.label ?? null;
const productType  = matchedProduct?.type ?? null;
const productValue = matchedProduct?.value ?? 0;

// ---------- PAYMENT STATUS ----------
const paymentSuccessful =
  input.has_valid_payment === true &&
  matchedProduct !== null &&
  isSamePerson;

// ---------- CURRENT VALUES (null-safe) ----------
const previousCredits     = input["Previous credits"]     != null ? Number(input["Previous credits"])     : null;
const previousSubmissions = input["Previous Submissions"] != null ? Number(input["Previous Submissions"]) : null;

// ---------- CREDIT / SUBMISSION ADD & DEDUCT ----------
let creditsToAdd = 0;
let submissionsToAdd = 0;
let creditsToDeduct = 0;
let submissionsToDeduct = 0;
let deductedFrom = null;

if (paymentSuccessful) {
  // Add purchased product
  if (productType === "credits") {
    creditsToAdd = productValue;
  }
  if (productType === "submissions") {
    submissionsToAdd = productValue;
  }

  // Deduct 1 credit or 1 submission for the service
  // Credits are deducted first, then submissions as fallback
  if (previousCredits != null && previousCredits > 0) {
    creditsToDeduct = 1;
    deductedFrom = "credits";
  } else if (previousSubmissions != null && previousSubmissions > 0) {
    submissionsToDeduct = 1;
    deductedFrom = "submissions";
  }
}

// ---------- UPDATED VALUES ----------
const updatedCredits     = previousCredits     != null ? previousCredits     + creditsToAdd     - creditsToDeduct     : creditsToAdd     || null;
const updatedSubmissions = previousSubmissions != null ? previousSubmissions + submissionsToAdd - submissionsToDeduct : submissionsToAdd || null;

// ---------- NOTE ----------
let note;
if (!input.has_valid_payment) {
  note = "Payment failed";
} else if (!matchedProduct) {
  note = "Unknown payment amount";
} else if (!isSamePerson) {
  note = "Payment user does not match database user";
} else {
  note = `Payment successful — ${productLabel}${deductedFrom ? ` | 1 ${deductedFrom} deducted` : ""}`;
}

// ---------- OUTPUT ----------
const output = {
  payment_successful: paymentSuccessful,

  payer_name: paymentName,
  database_name: dbName,

  payer_email: paymentEmail,
  database_email: dbEmail,

  bundle: productLabel,
  bundle_type: productType,

  credits_added: creditsToAdd,
  submissions_added: submissionsToAdd,

  credits_deducted: creditsToDeduct,
  submissions_deducted: submissionsToDeduct,

  deducted_from: deductedFrom,

  failure_message: $input.first().json.failure_message,

  note
};

// Only include updated values if they have a real value
if (updatedCredits     != null) output.updated_credits     = updatedCredits;
if (updatedSubmissions != null) output.updated_submissions = updatedSubmissions;

return [{ json: output }];

